6840: // ValidateSecretUpdate tests if required fields in the Secret are set.
6841: func ValidateSecretUpdate(newSecret, oldSecret *core.Secret) field.ErrorList {
6842: 	allErrs := ValidateObjectMetaUpdate(&newSecret.ObjectMeta, &oldSecret.ObjectMeta, field.NewPath("metadata"))
6843: 
6844: 	allErrs = append(allErrs, ValidateImmutableField(newSecret.Type, oldSecret.Type, field.NewPath("type"))...)
6845: 	if oldSecret.Immutable != nil && *oldSecret.Immutable {
6846: 		if newSecret.Immutable == nil || !*newSecret.Immutable {
6847: 			allErrs = append(allErrs, field.Forbidden(field.NewPath("immutable"), "field is immutable when `immutable` is set"))
6848: 		}
6849: 		if !reflect.DeepEqual(newSecret.Data, oldSecret.Data) {
6850: 			allErrs = append(allErrs, field.Forbidden(field.NewPath("data"), "field is immutable when `immutable` is set"))
6851: 		}
6852: 		// We don't validate StringData, as it was already converted back to Data
6853: 		// before validation is happening.
6854: 	}
6855: 
6856: 	allErrs = append(allErrs, ValidateSecret(newSecret)...)
6857: 	return allErrs
6858: }
