6867: 	allErrs := field.ErrorList{}
6868: 	allErrs = append(allErrs, ValidateObjectMeta(&cfg.ObjectMeta, true, ValidateConfigMapName, field.NewPath("metadata"))...)
6869: 
6870: 	totalSize := 0
6871: 
6872: 	for key, value := range cfg.Data {
6873: 		for _, msg := range validation.IsConfigMapKey(key) {
6874: 			allErrs = append(allErrs, field.Invalid(field.NewPath("data").Key(key), key, msg))
6875: 		}
6876: 		// check if we have a duplicate key in the other bag
6877: 		if _, isValue := cfg.BinaryData[key]; isValue {
